// Validate that multiple source rows don't match the same target row.
    // Per the Delta Lake protocol, MERGE must raise an error when multiple
    // source rows match a single target row, since the result would be
    // non-deterministic.
    {
        let group_cols: Vec<Expr> = snapshot
            .schema()
            .fields()
            .map(|f| {
                col(Column::new(
                    target_alias
                        .as_ref()
                        .map(|a| TableReference::bare(a.clone())),
                    f.name(),
                ))
            })
            .collect();

        let state_for_check = state.clone();
        let batches = join
            .clone()
            .filter(
                col(SOURCE_COLUMN)
                    .is_true()
                    .and(col(TARGET_COLUMN).is_true()),
            )?
            .aggregate(
                group_cols,
                vec![datafusion::functions_aggregate::count::count(
                    lit(1u8),
                )
                .alias("__delta_rs_match_count")],
            )?
            .filter(col("__delta_rs_match_count").gt(lit(1u8)))?
            .limit(0, Some(1))?
            .collect()
            .await?;

        if !batches.is_empty() && batches.iter().any(|b| b.num_rows() > 0) {
            return Err(DeltaTableError::Generic(
                "Multiple source rows matched the same target row. \
                 Ensure that each target row matches at most one source row \
                 (the merge condition must be deterministic)."
                    .into(),
            ));
        }

        // Re-create state since it was consumed
        drop(state_for_check);
    }

